import java.io.File;
import java.io.FileWriter;
import java.io.IOException;

import org.apache.commons.text.StringEscapeUtils;

public class XSSSecureCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Properly handle user input by writing it to a webpage
        try (FileWriter fileWriter = new FileWriter(new File("output.html"))) {
            fileWriter.write("<html><head><title>XSS Secure Code Demo</title></head><body>");
            fileWriter.write("<h1>Welcome, " + sanitizedInput + "</h1>");
            fileWriter.write("</body></html>");
            System.out.println("Output written to output.html");
        } catch (IOException e) {
            System.err.println("Error writing output: " + e.getMessage());
        }
    }
}

